import"./assets/modulepreload-polyfill.js";document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("status"),n=document.getElementById("startBtn");chrome.runtime.sendMessage({type:"GET_STATUS"},t=>{t!=null&&t.active&&(e.innerText="Status: ACTIVE",e.style.color="#00f0ff",n.innerText="System Running",n.disabled=!0)}),n.addEventListener("click",()=>{e.innerText="Menghubungkan ke Engine...",chrome.runtime.sendMessage({type:"START_NEURAL_ENGINE"},t=>{t!=null&&t.success&&(e.innerText="Status: ACTIVE",e.style.color="#00f0ff",n.innerText="System Running",n.disabled=!0)})})});
